	var NEW_HEARING_VENUE_TMP_PATH = "/ds/var/page/Tmp/JudgmentCourt";
	var NEW_HEARING_TMP_PATH = "/ds/var/page/Tmp/Hearing";
	var COURT_DATA_XPATH_ROOT = REF_DATA_XPATH + "/Courts";
	
	function setHomeCrtDetails() {			   	
	   	var hcrtcode  =  WPU.getHomeCourtCode();		   
	   	var addxpath = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/ContactDetails/Address"; 
	   	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/Name";
   		Services.setValue(JudgmentCourtCode.dataBinding, hcrtcode);
	   	Services.setValue(JudgmentCourt_VenueCode.dataBinding, hcrtcode);
	   	Services.setValue( JudgmentCourtName.dataBinding, Services.getValue(xpathName));	
	   	var addAr = Services.getNodes( addxpath );
	    if( null != addAr && addAr.length == 1) {				   	 	
	   	 	var ln1 = Services.getValue( addxpath+"/Line[1]" );
	   	 	var ln2 = Services.getValue( addxpath+"/Line[2]" );
	   	 	var ln3 = Services.getValue( addxpath+"/Line[3]" );
	   	 	var ln4 = Services.getValue( addxpath+"/Line[4]" );
	   	 	var ln5 = Services.getValue( addxpath+"/Line[5]" );
	   	 	var pcode = Services.getValue( addxpath+"/PostCode" );
	   	 	Services.setValue(CourtAdLine1.dataBinding, ln1);
		 	Services.setValue(CourtAdLine2.dataBinding, ln2);
		 	Services.setValue(CourtAdLine3.dataBinding, ln3);
		 	Services.setValue(CourtAdLine4.dataBinding, ln4);
		 	Services.setValue(CourtAdLine5.dataBinding, ln5);
		 	Services.setValue(CourtPostcode.dataBinding, pcode ); } }						


	function JudgmentCourtCode(){}
	JudgmentCourtCode.dataBinding = "/ds/EnterVariableData/AttendForQuestion/judgmentCourtCode";
	JudgmentCourtCode.isReadOnly = function(){ return true; }
	//JudgmentCourtCode.tabIndex = __tabIdx++;
	JudgmentCourtCode.maxLength = 3;
	JudgmentCourtCode.helpText = "Unique LCD three digit court location code – list available";
	JudgmentCourtCode.mandatoryOn = [JudgmentCourtName.dataBinding];
	JudgmentCourtCode.isMandatory = function()	{	return JudgmentCourtName.isMandatory();	}
	JudgmentCourtCode.enableOn = [JudgmentCourtName.dataBinding];
	JudgmentCourtCode.isEnabled = function() {	var isEbld = JudgmentCourtName.isEnabled();	return isEbld; }
	JudgmentCourtCode.logicOn = [JudgmentCourtCode.dataBinding];
	JudgmentCourtCode.logic = function() {   
		var code = Services.getValue(JudgmentCourtCode.dataBinding);		     		
     	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourtCode.dataBinding + "]/Name";	 
	 	var venueName = Services.getValue(xpathName); 	 
        Services.setValue(JudgmentCourtName.dataBinding, venueName);
		Services.setValue(JudgmentCourtCode.dataBinding, code);
        Services.setValue(JudgmentCourt_VenueName.dataBinding, code);
		Services.setValue(JudgmentCourt_VenueCode.dataBinding, code);
		var address = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourtCode.dataBinding + "]/ContactDetails/Address";		
		if( Services.countNodes(address) == 1) {
		    var xid    = Services.getValue(address + "/Id");
		    var line1  = Services.getValue(address + "/Line[1]");
		    var line2  = Services.getValue(address + "/Line[2]");
		    var line3  = Services.getValue(address + "/Line[3]");
		    var line4  = Services.getValue(address + "/Line[4]");
		    var line5  = Services.getValue(address + "/Line[5]");
		    var pcode  = Services.getValue(address + "/PostCode");
		    Services.setValue(REF_DATA_XPATH + "/Address/AddressId", xid);	
		    Services.setValue(CourtAdLine1.dataBinding,line1);		   
		    Services.setValue(CourtAdLine2.dataBinding,line2);
		    Services.setValue(CourtAdLine3.dataBinding,line3);
		    Services.setValue(CourtAdLine4.dataBinding,line4);
		    Services.setValue(CourtAdLine5.dataBinding,line5);
		    Services.setValue(CourtPostcode.dataBinding,pcode); }
		else {   
		    Services.setValue(NEW_HEARING_TMP_PATH + "/Address/AddressId", '');	
		    Services.setValue(CourtAdLine1.dataBinding,'');		   
		    Services.setValue(CourtAdLine2.dataBinding,'');
		    Services.setValue(CourtAdLine3.dataBinding,'');
		    Services.setValue(CourtAdLine4.dataBinding,'');
		    Services.setValue(CourtAdLine5.dataBinding,'');
		    Services.setValue(CourtPostcode.dataBinding,''); } }
		    
	function JudgmentCourtLOVBtn() {}
	JudgmentCourtLOVBtn.tabIndex = __tabIdx++;
	JudgmentCourtLOVBtn.actionBinding = function() {
		Services.dispatchEvent("JudgmentCrt_Popup", PopupGUIAdaptor.EVENT_RAISE); 
		var venueCode = Services.getValue(JudgmentCourtCode.dataBinding);
		Services.setValue(JudgmentCourt_VenueCode.dataBinding, venueCode); }
	
	JudgmentCourtLOVBtn.mandatoryOn = [JudgmentCourtName.dataBinding];
	JudgmentCourtLOVBtn.isMandatory = function() { return JudgmentCourtName.isMandatory(); }
	
	JudgmentCourtLOVBtn.enableOn = [JudgmentCourtName.dataBinding];
	JudgmentCourtLOVBtn.isEnabled = function() { return JudgmentCourtName.isEnabled(); }

    JudgmentCourtLOVBtn.additionalBindings = {
	    eventBinding: {
		    keys: [ { key: Key.F6, element: "JudgmentCourtCode" }, { key: Key.F6, element: "JudgmentCourtName" } ]
	    }
    };
	
	function JudgmentCrt_Popup(){}
	
	JudgmentCrt_Popup.firstFocusedAdaptorId = function() {
		return 'JudgmentCourt_VenueCode'; }
	
	JudgmentCrt_Popup.nextFocusedAdaptorId = function() {
		return 'JudgmentCourt_VenueLOVBtn'; }
			
	JudgmentCrt_Popup.lower = {
		eventBinding: {
			singleClicks: [ {element: "JudgmentCourt_CancelBtn"} ],
			keys: [ { key: Key.F4, element: "JudgmentCrt_Popup" } ]
		}
	};


	
	function JudgmentCourt_VenueCode(){}
	JudgmentCourt_VenueCode.dataBinding = "/ds/EnterVariableData/FastTrack/JudgmentCourt_VenueCode";
	JudgmentCourt_VenueCode.helpText = "Unique three digit court location code - list available.";
	JudgmentCourt_VenueCode.maxLength = 3;
	JudgmentCourt_VenueCode.logicOn = [JudgmentCourt_VenueCode.dataBinding];	
	JudgmentCourt_VenueCode.logic = function() {	
		var code = Services.getValue(JudgmentCourt_VenueCode.dataBinding);
		if(code != null && code != ""){
			Services.setValue(JudgmentCourt_VenueCode.dataBinding, code);	
			Services.setValue(JudgmentCourt_VenueName.dataBinding, code);		
			Services.setValue(JudgmentCourtCourtsLOVGrid.dataBinding, code); }
		else{
			Services.setValue(JudgmentCourt_VenueName.dataBinding, "");
			Services.setValue(JudgmentCourt_VenueCode.dataBinding, "");
			Services.setValue(JudgmentCourtCourtsLOVGrid.dataBinding, ""); } }	
	
    function JudgmentCourt_VenueName(){}
	JudgmentCourt_VenueName.dataBinding = "/ds/EnterVariableData/FastTrack/JudgmentCourt_VenueName";
	//JudgmentCourt_VenueName.tabIndex = __tabIdx++;
	JudgmentCourt_VenueName.isReadOnly = function(){ return false; }
	JudgmentCourt_VenueName.isTemporary = function(){ return true; }
	JudgmentCourt_VenueName.maxLength = 30;
	JudgmentCourt_VenueName.helpText = "Name of the Court.";
	JudgmentCourt_VenueName.isMandatory = function(){ return true; }
	JudgmentCourt_VenueName.validate = function(){ return null; }
	JudgmentCourt_VenueName.srcData = REF_DATA_XPATH + "/Courts";
	JudgmentCourt_VenueName.rowXPath = "Court";
	JudgmentCourt_VenueName.keyXPath = "Code";
	JudgmentCourt_VenueName.displayXPath = "Name";
	JudgmentCourt_VenueName.logicOn  = [JudgmentCourt_VenueName.dataBinding];
	JudgmentCourt_VenueName.logic = function() {
		var codeOrName = Services.getValue(JudgmentCourt_VenueName.dataBinding);      
		var xpath = REF_DATA_XPATH + "/Courts/Court[Code = " + JudgmentCourt_VenueName.dataBinding + "]/Code";
		var code = Services.getValue(xpath);
		if(code == null || "" == code) {
			var name = Services.getValue(JudgmentCourt_VenueName.dataBinding);     
			code = Services.getValue(REF_DATA_XPATH + "/Courts/Court[Name = " + JudgmentCourt_VenueName.dataBinding + "]/Code"); }
		if( code != null && code != "") { 	
			Services.setValue(JudgmentCourt_VenueCode.dataBinding, code); }
		else { 
			Services.setValue(JudgmentCourt_VenueName.dataBinding, "");
			Services.setValue(JudgmentCourt_VenueCode.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_Line1.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_Line2.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_Line3.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_Line4.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_Line5.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_Postcode.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_DXNumber.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_TelephoneNumber.dataBinding, "");
			Services.setValue(JudgmentCourt_ContactDetails_Address_FaxNumber.dataBinding, "");
			Services.setValue(JudgmentCourt_Address_Grid.dataBinding, ""); } }

