function JudgmentCourtCourtsLOVGrid() {};
JudgmentCourtCourtsLOVGrid.dataBinding = "/ds/var/page/SelectedLOVRow/Q382OwningCourt";
JudgmentCourtCourtsLOVGrid.srcData = REF_DATA_XPATH + "/Courts";
JudgmentCourtCourtsLOVGrid.rowXPath = "Court";
JudgmentCourtCourtsLOVGrid.keyXPath = "Code";
JudgmentCourtCourtsLOVGrid.columns = [ {xpath: "Code"}, {xpath: "Name"} ];
JudgmentCourtCourtsLOVGrid.logicOn = [JudgmentCourtCourtsLOVGrid.dataBinding];
JudgmentCourtCourtsLOVGrid.logic = function() {
	var courtCode = Services.getValue(JudgmentCourtCourtsLOVGrid.dataBinding);
	Services.setValue(JudgmentCourt_VenueCode.dataBinding, courtCode);
	Services.setValue(JudgmentCourt_VenueName.dataBinding, courtCode); }
JudgmentCourtCourtsLOVGrid.raise = {
	eventBinding: {
		singleClicks: [ {element: "JudgmentCourt_VenueLOVBtn"} ],
		keys: [ { key: Key.F6, element: "JudgmentCourt_VenueCode" }, { key: Key.F6, element: "JudgmentCourt_VenueName" } ] } };									
	

function JudgmentCourt_Address_Grid(){};
JudgmentCourt_Address_Grid.dataBinding = "/ds/var/page/SelectedJudgmentCourtGridRow/SelectedAddress"; 
JudgmentCourt_Address_Grid.srcData = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourtCourtsLOVGrid.dataBinding + "]/ContactDetails"; 
JudgmentCourt_Address_Grid.rowXPath = "Address";		// Individual Court/venue
JudgmentCourt_Address_Grid.keyXPath = "AddressId";  	// Unique identifier for a Court/venue
JudgmentCourt_Address_Grid.columns = [   				// column bindings
	{xpath: "Line[1]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}},
	{xpath: "Line[2]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}} ];
JudgmentCourt_Address_Grid.retrieveOn = [JudgmentCourtCourtsLOVGrid.dataBinding];
JudgmentCourt_Address_Grid.srcDataOn = [JudgmentCourtCourtsLOVGrid.dataBinding];
	
JudgmentCourt_Address_Grid.logicOn = [JudgmentCourt_Address_Grid.dataBinding, JudgmentCourtCourtsLOVGrid.dataBinding];
JudgmentCourt_Address_Grid.logic = function() {
	var courtCode = Services.getValue(JudgmentCourtCourtsLOVGrid.dataBinding);
	var addressId = Services.getValue(JudgmentCourt_Address_Grid.dataBinding);
	if (courtCode != null && addressId != null && "" != courtCode && "" != addressId){
		var b11 = REF_DATA_XPATH + "/Courts/Court[./Code = ";
		var b13 = "]/ContactDetails/";
		var b12 = b13 + "Address[./AddressId = ";
		var xpathAdd1 = b11+courtCode+b12+addressId+"]/Line[1]";	
		var xpathAdd2 = b11+courtCode+b12+addressId+"]/Line[2]";	
		var xpathAdd3 = b11+courtCode+b12+addressId+"]/Line[3]";	
		var xpathAdd4 = b11+courtCode+b12+addressId+"]/Line[4]";	
		var xpathAdd5 = b11+courtCode+b12+addressId+"]/Line[5]";	
		var xpathPostcode = b11+courtCode+b12+addressId+"]/PostCode";	
		var xpathDXNo  = b11+courtCode+b13+"DX";	
		var xpathTelNo = b11+courtCode+b13+"TelephoneNumber";	
		var xpathFaxNo = b11+courtCode+b13+"FaxNumber";	
		var add1 = Services.getValue(xpathAdd1);
		var add2 = Services.getValue(xpathAdd2);
		var add3 = Services.getValue(xpathAdd3);	if(add3==null) add3="";
		var add4 = Services.getValue(xpathAdd4);	if(add4==null) add4="";
		var add5 = Services.getValue(xpathAdd5);	if(add5==null) add5="";
		var postcode = Services.getValue(xpathPostcode);		
		var dxNo = Services.getValue(xpathDXNo); 	if(dxNo==null) dxNo="";
		var telNo = Services.getValue(xpathTelNo);	if(telNo==null) telNo="";
		var faxNo = Services.getValue(xpathFaxNo);  if(faxNo==null) faxNo="";
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line1.dataBinding, add1);
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line2.dataBinding, add2);
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line3.dataBinding, add3);
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line4.dataBinding, add4);
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line5.dataBinding, add5);
		Services.setValue(JudgmentCourt_ContactDetails_Address_Postcode.dataBinding, postcode);		
		Services.setValue(JudgmentCourt_ContactDetails_Address_DXNumber.dataBinding, dxNo);
		Services.setValue(JudgmentCourt_ContactDetails_Address_TelephoneNumber.dataBinding, telNo);
		Services.setValue(JudgmentCourt_ContactDetails_Address_FaxNumber.dataBinding, faxNo); }
	else {
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line1.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line2.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line3.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line4.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_Line5.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_Postcode.dataBinding, "");		
		Services.setValue(JudgmentCourt_ContactDetails_Address_DXNumber.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_TelephoneNumber.dataBinding, "");
		Services.setValue(JudgmentCourt_ContactDetails_Address_FaxNumber.dataBinding, ""); } }


	function JudgmentCourt_OKBtn(){}
	JudgmentCourt_OKBtn.actionBinding = function() {		
		var venueCode = Services.getValue(JudgmentCourt_VenueCode.dataBinding);
		var venueName = Services.getValue(JudgmentCourt_VenueName.dataBinding);
		var addressId = Services.getValue(JudgmentCourt_Address_Grid.dataBinding);
		var add1 = Services.getValue(JudgmentCourt_ContactDetails_Address_Line1.dataBinding);
		var add2 = Services.getValue(JudgmentCourt_ContactDetails_Address_Line2.dataBinding);	
		var add3 = Services.getValue(JudgmentCourt_ContactDetails_Address_Line3.dataBinding);	
		var add4 = Services.getValue(JudgmentCourt_ContactDetails_Address_Line4.dataBinding);
		var add5 = Services.getValue(JudgmentCourt_ContactDetails_Address_Line5.dataBinding);
		var postcode = Services.getValue(JudgmentCourt_ContactDetails_Address_Postcode.dataBinding);		
		var screenValid = true;
		if((venueCode == null || venueCode == "") || (venueName == null || venueName == "") || (add1 == null || add2 == "")) {
			screenValid = false; }
		if(screenValid) {	    
		 	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourt_VenueName.dataBinding + "]/Name";	 
		 	var checkVenueName = Services.getValue(xpathName);
		 	if( null != checkVenueName && checkVenueName.length > 0)  {  
	    		venueName = checkVenueName; }
			Services.setValue(JudgmentCourtCode.dataBinding, venueCode);		
			Services.setValue(JudgmentCourtName.dataBinding, venueName);
			Services.setValue(NEW_HEARING_TMP_PATH + "/Address/AddressId", addressId);
			Services.setValue(CourtAdLine1.dataBinding, add1);
			Services.setValue(CourtAdLine2.dataBinding, add2);			
			Services.setValue(CourtAdLine3.dataBinding, add3);
			Services.setValue(CourtAdLine4.dataBinding, add4);
			Services.setValue(CourtAdLine5.dataBinding, add5);
			Services.setValue(CourtPostcode.dataBinding, postcode);			
			var output = WP.GetScreenProcess().getOutput().getCJRReference();
			if(output == 'CJR093' || output == 'CJR094' || output == 'CJR091' ) {		
				var homeCode  =  WPU.getHomeCourtCode();
				var courtCode = Services.getValue(JudgmentCourtCode.dataBinding);
				if(homeCode == courtCode) {
					Services.setValue(JudgmentThisCourt.dataBinding,"Y"); }
				else {
					Services.setValue(JudgmentThisCourt.dataBinding,"N"); } }		
		FormController.getInstance().hideFormExtensionPopup("JudgmentCourt"); } }
	

	JudgmentCourt_OKBtn.enableOn = [NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[1]"];
	JudgmentCourt_OKBtn.isEnabled = function()  {	
		var c = Services.getValue(NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[1]");
		if(c != null && c!= "") {
			return true; }
		else {
			return false; } }

	function JudgmentCourt_CancelBtn(){}
	JudgmentCourt_CancelBtn.tabIndex = __tabIdx++;

