			JudgmentCourtName.courtDataLoadCallBack = function() {			
				Services.setValue(JudgmentCourtCode.dataBinding, WPU.getHomeCourtCode());
				var courtName = Services.getValue(REF_DATA_XPATH + "/Courts/Court[./Code = " + WPU.getHomeCourtCode() + "]/Name")					
				Services.setValue(JudgmentCourtName.dataBinding, courtName);
				Services.setValue(JudgmentCourt_VenueCode.dataBinding, WPU.getHomeCourtCode()); }


			JudgmentCourtName.courtDataLoadCallBack = function() {			
				Services.setValue(JudgmentCourtCode.dataBinding, WPU.getHomeCourtCode());
				var courtName = Services.getValue(REF_DATA_XPATH + "/Courts/Court[./Code = " + WPU.getHomeCourtCode() + "]/Name")					
				Services.setValue(JudgmentCourtName.dataBinding, courtName);
				Services.setValue(JudgmentCourt_VenueCode.dataBinding, WPU.getHomeCourtCode()); }

Context.isEnabled:
var N39En = IsN39Reqd.isEnabled();
var isN39Req = Services.getValue(IsN39Reqd.dataBinding);
var val1 = Services.getValue(JudgmentThisCourt.dataBinding);
return ( (!N39En || 'Y' == isN39Req) && 'Y' != val1 );

Context.logic:
var N39En = IsN39Reqd.isEnabled();
var isN39Req = Services.getValue(IsN39Reqd.dataBinding);
var val1 = Services.getValue(JudgmentThisCourt.dataBinding);
var courtCode = Services.getValue(JudgmentCourtCode.dataBinding);
var isEbld =  ( (!N39En || 'Y' == isN39Req) && 'Y' != val1 );
if(isEbld ) {	
	if( null == courtCode || "" == courtCode) {  	
		Services.setValue(JudgmentCourtCode.dataBinding, WPU.getHomeCourtCode()); } }
else {
